const { Pool } = require('pg');
require('dotenv').config();

// configure connection pool with environment variables
const pool = new Pool({
  user: process.env.PG_USER,
  host: process.env.PG_HOST,
  database: process.env.PG_DATABASE,
  password: process.env.PG_PASSWORD,
  port: process.env.PG_PORT,
});

// CRUD operations
const create = async (tableName, data) => {
  const keys = Object.keys(data).join(', ');
  const values = Object.values(data).map((value) => `'${value}'`).join(', ');
  const query = `INSERT INTO ${tableName} (${keys}) VALUES (${values});`;
  
  await pool.query(query);
};

const read = async (tableName, condition) => {
  let query = `SELECT * FROM ${tableName} WHERE `;
  
  for (let key in condition) {
    if (condition[key] instanceof Array) {
      query += `${key} IN (${condition[key].join(', ')}) AND `;
    } else {
      query += `${key} = '${condition[key]}' AND `;
    }
  }
  
  // remove trailing "AND" and space
  query = query.slice(0, -5);
  
  const result = await pool.query(query);
  return result.rows;
};

